import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  console.error("Could not find root element to mount to");
  throw new Error("Could not find root element to mount to");
}

try {
    const root = ReactDOM.createRoot(rootElement);
    root.render(
      <React.StrictMode>
        <App />
      </React.StrictMode>
    );
    console.log("Next2Dubai App mounted successfully");
} catch (error) {
    console.error("Failed to mount app:", error);
    // Visual feedback for debugging
    rootElement.innerHTML = `<div style="pointer-events: auto; background: white; padding: 20px; border: 2px solid red; color: red;">
      <strong>Error loading application:</strong><br/>
      ${error instanceof Error ? error.message : String(error)}
    </div>`;
}

