import { GoogleGenAI, Content, Part, GenerateContentResponse } from "@google/genai";
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL } from "../constants";

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

interface ChatResponse {
  text: string;
  toolCalls?: { name: string; args: any; id: string }[];
}

export const sendMessageToGemini = async (
  history: { role: 'user' | 'model'; text: string }[],
  newMessage: string
): Promise<ChatResponse> => {
  const ai = getClient();
  const modelId = "gemini-2.0-flash";

  const contents: Content[] = [
    ...history.map(msg => ({ role: msg.role, parts: [{ text: msg.text }] as Part[] })),
    { role: "user", parts: [{ text: newMessage }] as Part[] },
  ];

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }],
      },
    });

    const candidate = response.candidates?.[0];
    const toolCalls = candidate?.content?.parts
      ?.filter(part => !!part.functionCall)
      .map(part => ({
        name: part.functionCall!.name,
        args: part.functionCall!.args,
        id: part.functionCall!.id || 'unknown-id'
      }));

    if (toolCalls && toolCalls.length > 0) {
      return { text: response.text || "", toolCalls };
    }

    return { text: response.text || "I'm sorry, I didn't catch that." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

