import { sendMessageToGemini } from '../services/geminiService';
import { saveLeadToSupabase, checkStatusInSupabase } from '../services/supabaseService';
import { sendWhatsAppMessage } from '../services/messagingService';

interface ChatOverlayProps {
  isActive: boolean;
  onBack: () => void;
}

export const ChatOverlay: React.FC<ChatOverlayProps> = ({ isActive, onBack }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    if (isActive && messages.length === 0) {
      setMessages([{
        id: 'welcome',
        role: 'model',
        text: "Namaste! I am Neha. How can I help you with your job application or visa today?",
        timestamp: new Date()
      }]);
    }
  }, [isActive, messages.length]);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  const handleSendMessage = async (text: string) => {
    const userMsg: Message = { id: Date.now().toString(), role: 'user', text, timestamp: new Date() };
    setMessages(prev => [...prev, userMsg]);
    setIsLoading(true);

    try {
      const response = await sendMessageToGemini(
        messages.filter(m => !m.isError && m.role !== 'system').map(m => ({ role: m.role as 'user'|'model', text: m.text })),
        text
      );

      if (response.toolCalls) {
        for (const tool of response.toolCalls) {
          let toolResult = "Done.";
          if (tool.name === 'saveToExcel') {
             await saveLeadToSupabase(tool.args as LeadToolArgs);
             toolResult = "Saved details.";
          }
          if (tool.name === 'checkApplicationStatus') {
             const status = await checkStatusInSupabase(tool.args.identifier);
             toolResult = status.responseString;
          }
          if (tool.name === 'sendWhatsAppMessage') {
             await sendWhatsAppMessage(tool.args.phone, tool.args.message);
             toolResult = "Sent message.";
          }
          response.text += `\n\n[Action: ${toolResult}]`;
        }
      }

      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: response.text, timestamp: new Date() }]);
    } catch (error) {
      setMessages(prev => [...prev, { id: Date.now().toString(), role: 'model', text: "Network error. Please try again.", timestamp: new Date(), isError: true }]);
    } finally {
      setIsLoading(false);
    }
  };

  if (!isActive) return null;

  return (
    <div className="fixed inset-0 bg-slate-50 z-50 flex flex-col pointer-events-auto">
      <div className="flex items-center justify-between bg-white px-4 py-3 border-b border-slate-200">
         <button onClick={onBack} className="text-slate-500 font-medium">← Back</button>
         <span className="font-semibold text-slate-800">Chat with Neha</span>
         <div className="w-8"></div>
      </div>
      <div className="flex-1 overflow-y-auto p-4 space-y-6">
        {messages.map(msg => <MessageBubble key={msg.id} message={msg} />)}
        <div ref={messagesEndRef} />
      </div>
      <InputArea onSend={handleSendMessage} isLoading={isLoading} />
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { LeadNotification } from './components/LeadNotification';
import { CallOverlay } from './components/CallOverlay';
import { CallFloatingButton } from './components/CallFloatingButton';
import { ChatOverlay } from './components/ChatOverlay';
import { Lead, LeadToolArgs } from './types';
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL } from './constants';
import { createAudioBlob, decodeAudioData, AUDIO_INPUT_SAMPLE_RATE, AUDIO_OUTPUT_SAMPLE_RATE } from './services/audioUtils';
import { saveLeadToSupabase, checkStatusInSupabase } from './services/supabaseService';
import { sendWhatsAppMessage } from './services/messagingService';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type AppMode = 'idle' | 'call' | 'chat';

function App() {
  const [mode, setMode] = useState<AppMode>('idle');
  const [isCallConnected, setIsCallConnected] = useState(false);
  const [newLead, setNewLead] = useState<Lead | null>(null);
  const [volumeLevel, setVolumeLevel] = useState(0);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const sessionRef = useRef<Promise<any> | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);
  const currentLeadDataRef = useRef<Partial<LeadToolArgs>>({});

  const stopCall = async () => {
    // Save data if we have it
    if (currentLeadDataRef.current.contactInfo) {
      saveLeadToSupabase(currentLeadDataRef.current as LeadToolArgs);
    }

    // Stop tracks
    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    // Disconnect processors
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    // Close Audio Contexts
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }

    // Stop Audio Sources
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();

    // Close Session
    if (sessionRef.current) {
      try {
        const session = await sessionRef.current;
        session.close();
      } catch (e) {
        console.warn(e);
      }
      sessionRef.current = null;
    }

    setIsCallConnected(false);
    setMode('idle');
    setVolumeLevel(0);
    nextStartTimeRef.current = 0;
  };

  const startCall = async () => {
    setErrorMessage(null);
    const apiKey = process.env.API_KEY;
    if (!apiKey) {
      setErrorMessage("API Key missing.");
      return;
    }

    setMode('call');
    setIsCallConnected(false); 

    try {
      // Initialize Audio Contexts
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;

      const inputCtx = new AudioContextClass({ sampleRate: AUDIO_INPUT_SAMPLE_RATE });
      const outputCtx = new AudioContextClass({ sampleRate: AUDIO_OUTPUT_SAMPLE_RATE });

      inputAudioContextRef.current = inputCtx;
      outputAudioContextRef.current = outputCtx;

      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      mediaStreamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [{ functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }],
          speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Aoede' } } }
        },
        callbacks: {
            onopen: () => {
                console.log("Connected to Gemini Live");
                setIsCallConnected(true);

                if (!inputAudioContextRef.current) return;

                const source = inputAudioContextRef.current.createMediaStreamSource(stream);
                const processor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
                scriptProcessorRef.current = processor;

                processor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    // Volume calculation
                    let sum = 0;
                    for(let i=0; i<inputData.length; i++) sum += inputData[i]*inputData[i];
                    setVolumeLevel(Math.min(Math.sqrt(sum/inputData.length)*5, 1));

                    const pcmBlob = createAudioBlob(inputData);
                    sessionPromise.then(session => session.sendRealtimeInput({ media: pcmBlob }));
                };

                source.connect(processor);
                processor.connect(inputAudioContextRef.current.destination);

                // Trigger intro
                sessionPromise.then(s => s.sendRealtimeInput({ media: { mimeType: "audio/pcm;rate=16000", data: "" } }));
            },
            onmessage: async (message: LiveServerMessage) => {
                // Handle Audio
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (base64Audio && outputAudioContextRef.current) {
                    const ctx = outputAudioContextRef.current;
                    const audioBuffer = await decodeAudioData(base64Audio, ctx);

                    const now = ctx.currentTime;
                    // Ensure smooth scheduling
                    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, now);

                    const source = ctx.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(ctx.destination);
                    source.start(nextStartTimeRef.current);
                    nextStartTimeRef.current += audioBuffer.duration;

                    audioSourcesRef.current.add(source);
                    source.onended = () => audioSourcesRef.current.delete(source);
                }

                if (message.serverContent?.interrupted) {
                    audioSourcesRef.current.forEach(s => s.stop());
                    audioSourcesRef.current.clear();
                    if(outputAudioContextRef.current) nextStartTimeRef.current = outputAudioContextRef.current.currentTime;
                }

                // Handle Tools
                if (message.toolCall) {
                    for (const fc of message.toolCall.functionCalls) {
                        let result = {};
                        if (fc.name === 'saveToExcel') {
                             const args = fc.args as any;
                             currentLeadDataRef.current = args;
                             setNewLead({ id: Date.now().toString(), ...args, createdAt: new Date() });
                             saveLeadToSupabase(args);
                             result = { result: "Saved." };
                        }
                        if (fc.name === 'checkApplicationStatus') {
                            const r = await checkStatusInSupabase((fc.args as any).identifier);
                            result = { result: r.responseString };
                        }
                        if (fc.name === 'sendWhatsAppMessage') {
                            await sendWhatsAppMessage((fc.args as any).phone, (fc.args as any).message);
                            result = { result: "Sent." };
                        }

                        sessionPromise.then(s => s.sendToolResponse({
                            functionResponses: { name: fc.name, id: fc.id, response: result }
                        }));
                    }
                }
            },
            onclose: () => stopCall(),
            onerror: (err) => {
                console.error(err);
                setErrorMessage("Connection failed.");
                stopCall();
            }
        }
      });
      sessionRef.current = sessionPromise;
    } catch (err) {
      console.error(err);
      setErrorMessage("Could not start call.");
      stopCall();
    }
  };

  return (
    <div className="w-full h-full relative">
      {errorMessage && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 bg-red-100 text-red-700 px-4 py-2 rounded-lg z-[100] text-sm pointer-events-auto">
          {errorMessage} <button onClick={() => setErrorMessage(null)} className="ml-2 font-bold">X</button>
        </div>
      )}

      {mode === 'idle' && (
        <CallFloatingButton 
            onStartCall={startCall} 
            onStartChat={() => setMode('chat')} 
            isCallActive={false}
        />
      )}

      <CallOverlay 
        isActive={mode === 'call'} 
        isConnected={isCallConnected} 
        onEndCall={stopCall} 
        volumeLevel={volumeLevel} 
      />

      <ChatOverlay isActive={mode === 'chat'} onBack={() => setMode('idle')} />
      <LeadNotification lead={newLead} onClose={() => setNewLead(null)} />
    </div>
  );
}

export default App;

import { GoogleGenAI, Content, Part, GenerateContentResponse } from "@google/genai";
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL } from "../constants";

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    // Uses the API_KEY from environment directly
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

interface ChatResponse {
  text: string;
  toolCalls?: { name: string; args: any; id: string }[];
}

export const sendMessageToGemini = async (
  history: { role: 'user' | 'model'; text: string }[],
  newMessage: string
): Promise<ChatResponse> => {
  const ai = getClient();
  // Using gemini-2.5-flash as per latest guidelines for text tasks
  const modelId = "gemini-2.5-flash";

  const contents: Content[] = [
    ...history.map(msg => ({ role: msg.role, parts: [{ text: msg.text }] as Part[] })),
    { role: "user", parts: [{ text: newMessage }] as Part[] },
  ];

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }],
      },
    });

    const candidate = response.candidates?.[0];
    const toolCalls = candidate?.content?.parts
      ?.filter(part => !!part.functionCall)
      .map(part => ({
        name: part.functionCall!.name,
        args: part.functionCall!.args,
        id: part.functionCall!.id || 'unknown-id'
      }));

    if (toolCalls && toolCalls.length > 0) {
      return { text: response.text || "", toolCalls };
    }

    return { text: response.text || "I'm sorry, I didn't catch that." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

