import React, { useState, useRef, useEffect } from 'react';
import { LeadNotification } from './components/LeadNotification';
import { CallOverlay } from './components/CallOverlay';
import { CallFloatingButton } from './components/CallFloatingButton';
import { ChatOverlay } from './components/ChatOverlay';
import { Lead, LeadToolArgs } from './types';
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL, CHECK_EMPLOYEE_TOOL } from './constants';
import { createAudioBlob, decodeAudioData, AUDIO_INPUT_SAMPLE_RATE, AUDIO_OUTPUT_SAMPLE_RATE, createSilentAudio } from './services/audioUtils';
import { saveLeadToSupabase, checkStatusInSupabase, checkEmployeeInSupabase } from './services/supabaseService';
import { sendWhatsAppMessage } from './services/messagingService';
import { GoogleGenAI, LiveServerMessage, Modality } from "@google/genai";

type AppMode = 'idle' | 'call' | 'chat';

function App() {
  const [mode, setMode] = useState<AppMode>('idle');
  const [isCallConnected, setIsCallConnected] = useState(false); 
  const [newLead, setNewLead] = useState<Lead | null>(null);
  const [volumeLevel, setVolumeLevel] = useState(0);
  const [errorMessage, setErrorMessage] = useState<string | null>(null);

  const sessionRef = useRef<Promise<any> | null>(null);
  const inputAudioContextRef = useRef<AudioContext | null>(null);
  const outputAudioContextRef = useRef<AudioContext | null>(null);
  const mediaStreamRef = useRef<MediaStream | null>(null);
  const scriptProcessorRef = useRef<ScriptProcessorNode | null>(null);
  const audioSourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());
  const nextStartTimeRef = useRef<number>(0);

  const currentLeadDataRef = useRef<Partial<LeadToolArgs>>({});

  useEffect(() => {
     window.parent.postMessage({ type: 'resize-widget', view: 'full' }, '*');
  }, [mode]);

  const stopCall = async () => {
    if (currentLeadDataRef.current.contactInfo) {
      const finalLead: LeadToolArgs = {
        customerName: currentLeadDataRef.current.customerName || "Anonymous Caller",
        contactInfo: currentLeadDataRef.current.contactInfo || "Not Provided",
        interest: currentLeadDataRef.current.interest || "General Inquiry",
        language: currentLeadDataRef.current.language || "en",
        summary: `[AI SUMMARY]\n${currentLeadDataRef.current.summary || "No AI summary generated."}`,
        city: currentLeadDataRef.current.city,
        experience: currentLeadDataRef.current.experience,
        passportStatus: currentLeadDataRef.current.passportStatus,
        age: currentLeadDataRef.current.age,
        remarks: currentLeadDataRef.current.remarks || "Call ended.",
        bestCallTime: currentLeadDataRef.current.bestCallTime
      };
      saveLeadToSupabase(finalLead);
    }

    if (mediaStreamRef.current) {
      mediaStreamRef.current.getTracks().forEach(track => track.stop());
      mediaStreamRef.current = null;
    }
    if (scriptProcessorRef.current) {
      scriptProcessorRef.current.disconnect();
      scriptProcessorRef.current = null;
    }
    if (inputAudioContextRef.current) {
      inputAudioContextRef.current.close();
      inputAudioContextRef.current = null;
    }
    audioSourcesRef.current.forEach(source => source.stop());
    audioSourcesRef.current.clear();
    if (outputAudioContextRef.current) {
      outputAudioContextRef.current.close();
      outputAudioContextRef.current = null;
    }

    // Cleanly close the session if it exists
    if (sessionRef.current) {
        try {
            const session = await sessionRef.current;
            session.close();
        } catch (e) {
            console.warn("Session close error:", e);
        }
        sessionRef.current = null;
    }

    setIsCallConnected(false);
    setMode('idle');
    setVolumeLevel(0);
    nextStartTimeRef.current = 0;
    currentLeadDataRef.current = {};
  };

  const startCall = async () => {
    setErrorMessage(null);
    if (!process.env.API_KEY) {
      setErrorMessage("API Key is missing.");
      return;
    }

    setMode('call');
    setIsCallConnected(false);

    try {
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      inputAudioContextRef.current = new AudioContextClass({ 
        sampleRate: AUDIO_INPUT_SAMPLE_RATE,
        latencyHint: 'interactive'
      });
      outputAudioContextRef.current = new AudioContextClass({ sampleRate: AUDIO_OUTPUT_SAMPLE_RATE });

      if (outputAudioContextRef.current.state === 'suspended') {
          await outputAudioContextRef.current.resume();
      }

      let stream: MediaStream;
      try {
        stream = await navigator.mediaDevices.getUserMedia({ 
            audio: {
                echoCancellation: true,
                noiseSuppression: true,
                autoGainControl: true,
                channelCount: 1
            } 
        });
      } catch (micErr) {
        console.error("Mic Error:", micErr);
        setErrorMessage("Microphone access denied.");
        setMode('idle');
        return;
      }

      mediaStreamRef.current = stream;

      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        config: {
          responseModalities: [Modality.AUDIO],
          systemInstruction: SYSTEM_INSTRUCTION,
          tools: [
            { functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, CHECK_EMPLOYEE_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }
          ],
          speechConfig: {
            voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Aoede' } }
          }
        },
        callbacks: {
            onopen: () => {
                console.log("Connection Established");
                setErrorMessage(null);
                setIsCallConnected(true);

                // SEND SILENT WAKE-UP PULSE
                const silentPulse = createSilentAudio(100); 
                sessionPromise.then(session => {
                    session.sendRealtimeInput({ media: silentPulse });
                });

                if (!inputAudioContextRef.current) return;
                const source = inputAudioContextRef.current.createMediaStreamSource(stream);
                const processor = inputAudioContextRef.current.createScriptProcessor(4096, 1, 1);
                scriptProcessorRef.current = processor;

                processor.onaudioprocess = (e) => {
                    const inputData = e.inputBuffer.getChannelData(0);
                    let sum = 0;
                    for(let i = 0; i < inputData.length; i++) sum += inputData[i] * inputData[i];
                    const rms = Math.sqrt(sum / inputData.length);
                    setVolumeLevel(Math.min(rms * 5, 1));

                    if (rms > 0.01) { 
                        const pcmBlob = createAudioBlob(inputData);
                        sessionPromise.then(session => {
                            session.sendRealtimeInput({ media: pcmBlob });
                        }).catch(e => console.error("Send Error:", e));
                    }
                };
                source.connect(processor);
                processor.connect(inputAudioContextRef.current!.destination);
            },
            onmessage: async (message: LiveServerMessage) => {
                const base64Audio = message.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
                if (base64Audio && outputAudioContextRef.current) {
                    if (outputAudioContextRef.current.state === 'suspended') {
                        await outputAudioContextRef.current.resume();
                    }
                    const ctx = outputAudioContextRef.current;
                    nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
                    const audioBuffer = await decodeAudioData(base64Audio, ctx);
                    const source = ctx.createBufferSource();
                    source.buffer = audioBuffer;
                    source.connect(ctx.destination);
                    source.addEventListener('ended', () => {
                        audioSourcesRef.current.delete(source);
                    });
                    source.start(nextStartTimeRef.current);
                    nextStartTimeRef.current += audioBuffer.duration;
                    audioSourcesRef.current.add(source);
                }

                if (message.serverContent?.interrupted) {
                    audioSourcesRef.current.forEach(src => src.stop());
                    audioSourcesRef.current.clear();
                    if (outputAudioContextRef.current) {
                        nextStartTimeRef.current = outputAudioContextRef.current.currentTime;
                    }
                }

                if (message.toolCall) {
                    for (const fc of message.toolCall.functionCalls) {
                        let resultResponse = {};
                        if (fc.name === 'saveToExcel') {
                             const args = fc.args as unknown as LeadToolArgs;
                             currentLeadDataRef.current = { ...currentLeadDataRef.current, ...args };
                             setNewLead({
                               id: Date.now().toString(),
                               customerName: args.customerName,
                               contactInfo: args.contactInfo,
                               interest: args.interest,
                               language: args.language || 'en',
                               summary: args.summary,
                               createdAt: new Date()
                             });
                             saveLeadToSupabase(args);
                             resultResponse = { result: "Saved." };
                        }
                        if (fc.name === 'checkApplicationStatus') {
                            const identifier = (fc.args as any).identifier;
                            const statusResult = await checkStatusInSupabase(identifier);
                            resultResponse = { result: statusResult.responseString };
                        }
                        if (fc.name === 'checkEmployeeStatus') {
                            const identifier = (fc.args as any).identifier;
                            const empResult = await checkEmployeeInSupabase(identifier);
                            resultResponse = { result: empResult.responseString };
                        }
                        if (fc.name === 'navigateWebsite') {
                            window.parent.postMessage({ type: 'navigate', path: (fc.args as any).path }, '*');
                            resultResponse = { result: "Done." };
                        }
                        if (fc.name === 'sendWhatsAppMessage') {
                            await sendWhatsAppMessage((fc.args as any).phone, (fc.args as any).message);
                            resultResponse = { result: "Sent." };
                        }

                        sessionPromise.then(session => {
                            session.sendToolResponse({
                                functionResponses: { name: fc.name, id: fc.id, response: resultResponse }
                            });
                        });
                    }
                }
            },
            onclose: () => stopCall(),
            onerror: (err) => {
                console.error("Live API Error:", err);
                setErrorMessage("Connection interrupted. Retrying...");
                setTimeout(() => {
                   if (sessionRef.current) { stopCall(); startCall(); }
                }, 2000);
            }
        }
      });
      sessionRef.current = sessionPromise;
    } catch (err) {
      console.error("Setup Error:", err);
      setErrorMessage("Network Error.");
      setMode('idle');
      setIsCallConnected(false);
    }
  };

  return (
    <div className="w-full h-full relative">
      {errorMessage && (
        <div className="fixed top-4 left-1/2 -translate-x-1/2 bg-red-50 border border-red-200 text-red-600 px-4 py-2 rounded-full shadow-lg z-[100] text-sm font-medium pointer-events-auto">
          {errorMessage} <button onClick={() => { setErrorMessage(null); startCall(); }} className="underline ml-2">Retry</button>
        </div>
      )}

      {mode === 'idle' && (
        <CallFloatingButton 
            onStartCall={startCall} 
            onStartChat={() => setMode('chat')} 
            isCallActive={false}
        />
      )}

      <CallOverlay 
        isActive={mode === 'call'} 
        isConnected={isCallConnected}
        onEndCall={stopCall} 
        volumeLevel={volumeLevel} 
      />

      <ChatOverlay isActive={mode === 'chat'} onBack={() => setMode('idle')} />

      <LeadNotification lead={newLead} onClose={() => setNewLead(null)} />
    </div>
  );
}

export default App;

import { GoogleGenAI, Content, Part, GenerateContentResponse } from "@google/genai";
import { SYSTEM_INSTRUCTION, CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, CHECK_EMPLOYEE_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL } from "../constants";
import { LeadToolArgs } from "../types";

let aiClient: GoogleGenAI | null = null;

const getClient = () => {
  if (!aiClient) {
    aiClient = new GoogleGenAI({ apiKey: process.env.API_KEY });
  }
  return aiClient;
};

interface ChatResponse {
  text: string;
  toolCalls?: { name: string; args: any; id: string }[];
}

export const sendMessageToGemini = async (
  history: { role: 'user' | 'model'; text: string }[],
  newMessage: string
): Promise<ChatResponse> => {
  const ai = getClient();
  const modelId = "gemini-2.5-flash";

  const formattedHistory: Content[] = history.map(msg => ({
    role: msg.role,
    parts: [{ text: msg.text }] as Part[]
  }));

  const contents: Content[] = [
    ...formattedHistory,
    { role: "user", parts: [{ text: newMessage }] as Part[] },
  ];

  try {
    const response: GenerateContentResponse = await ai.models.generateContent({
      model: modelId,
      contents: contents,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION,
        tools: [{ functionDeclarations: [CREATE_LEAD_TOOL, CHECK_STATUS_TOOL, CHECK_EMPLOYEE_TOOL, NAVIGATE_WEBSITE_TOOL, SEND_WHATSAPP_TOOL] }],
      },
    });

    const candidate = response.candidates?.[0];

    const toolCalls = candidate?.content?.parts
      ?.filter(part => !!part.functionCall)
      .map(part => ({
        name: part.functionCall!.name,
        args: part.functionCall!.args,
        id: part.functionCall!.id || 'unknown-id'
      }));

    if (toolCalls && toolCalls.length > 0) {
      return { text: response.text || "", toolCalls };
    }

    return { text: response.text || "I'm sorry, I didn't catch that." };
  } catch (error) {
    console.error("Gemini API Error:", error);
    throw error;
  }
};

